// Color harmony utilities based on golden ratio
utility ColorHarmony {
  const PHI = 1.618033988749895
  const GOLDEN_ANGLE = 137.5

  // Generate golden ratio color palette
  function goldenPalette(baseHue, count) {
    let colors = []
    for (let i = 0; i < count; i++) {
      let hue = (baseHue + i * GOLDEN_ANGLE) % 360
      colors.push(`hsl(${hue}, 70%, 55%)`)
    }
    return colors
  }

  // Fibonacci saturation steps
  function fibonacciShades(baseColor, steps) {
    let fib = [1, 1, 2, 3, 5, 8, 13, 21]
    let total = fib.slice(0, steps).reduce((a, b) => a + b, 0)
    return fib.slice(0, steps).map((f, i) => {
      let lightness = 30 + (f / total) * 50
      return `hsl(${baseColor}, 70%, ${lightness}%)`
    })
  }
}

scene ColorShowcase {
