// Custom golden ratio easing functions
easing {
  // Deceleration using phi
  goldenEaseOut: (t) => {
    const PHI = 1.618033988749895
    return 1 - Math.pow(1 - t, PHI)
  }

  // Acceleration using phi
  goldenEaseIn: (t) => {
    const PHI = 1.618033988749895
    return Math.pow(t, PHI)
  }

  // Both using phi
  goldenEaseInOut: (t) => {
    const PHI = 1.618033988749895
    return t < 0.5
      ? Math.pow(2 * t, PHI) / 2
      : 1 - Math.pow(2 * (1 - t), PHI) / 2
  }

  // Fibonacci bounce
  fibonacciBounce: (t) => {
    const bounces = [0.363, 0.727, 0.909, 0.97, 0.99, 1]  // Fib ratios
    const heights = [1, 0.618, 0.382, 0.236, 0.146, 0]    // PHI decay

    for (let i = 0; i < bounces.length; i++) {
      if (t < bounces[i]) {
        let prev = i > 0 ? bounces[i-1] : 0
        let progress = (t - prev) / (bounces[i] - prev)
        let peak = heights[i]
        return 1 - peak * Math.sin(progress * Math.PI)
      }
    }
    return 1
  }
}

