```holoscript
meta {
  id: "ARENA_001"
  name: "Golden Arena"
  maxPlayers: 8
  physics: "rapier3d"
  networking: "websocket-reliable"
}

scene GoldenArena {
  const PHI = 1.618

  environment: {
    skybox: 'nebula_hdri'
    ambientLight: 0.15
    postProcessing: { bloom: { intensity: 0.8 } }
  }

  network: { tickRate: 60, interpolation: true }
  physics: { gravity: -9.81, substeps: 4 }

  // === ARENA FLOOR ===
  object Floor @collidable {
    geometry: 'plane'
    size: [50, 50]
    material: {
      type: 'pbr'
      albedo: 'textures/hex_grid.png'
      emissive: '#4a00e0'
      emissiveIntensity: 0.3
    }
  }

  // === PILLARS (Golden angle distribution) ===
  object[] Pillars @collidable {
    count: 8

    distribution: {
      pattern: 'custom'
      generator: (i) => {
        let angle = i * 137.5 * (Math.PI / 180)
        let radius = 20
        return { position: [Math.cos(angle) * radius, 7.5, Math.sin(angle) * radius] }
      }
    }

    geometry: 'cylinder'
    radius: 1.5
    height: 15
    material: { type: 'glass', transparency: 0.7, tint: '#8b5cf6' }
  }

  // === PLAYER TEMPLATE ===
  template PlayerAvatar @networked {
    geometry: 'model/player_rig.glb'

    @networked position
    @networked rotation
    @networked health: 100
    @networked shield: 50
    @networked team: null

    stateMachine PlayerState {
      initial: 'alive'
      states: {
        alive: { transitions: { die: 'dying' } }
        dying: {
          enter: { particles.spawn('death_explosion', this.position) }
          after: 500 -> 'spectating'
        }
        spectating: {
          enter: { this.visible = false }
          transitions: { respawn: 'respawning' }
        }
        respawning: {
          enter: { this.health = 100; this.shield = 50 }
          after: 1000 -> 'alive'
        }
      }
    }

    children: {
      ui HealthBar { position: [0, 2.2, 0], billboard: true, bar: { current: () => this.health, max: 100 } }
    }
  }

  // === WEAPONS ===
  template Weapon @grabbable @networked {
    abstract: true
    @networked owner: null
    @networked ammo: 0
    physics: { mass: 0.8 }

    onGrab(player): {
      if (network.requestOwnership(this)) {
        this.owner = player.id
        player.equipped = this.id
      }
    }
  }

  object PlasmaPistol extends Weapon {
    geometry: 'model/plasma_pistol.glb'
    ammo: 20
    stats: { damage: 15, projectileSpeed: 50 }

    onFire: {
      if (this.ammo <= 0) return
      this.ammo--
      spawn(Projectile, {
        position: this.muzzle.worldPosition,
        velocity: this.muzzle.forward * this.stats.projectileSpeed,
        damage: this.stats.damage
      })
      particles.spawn('muzzle_flash', this.muzzle.worldPosition)
      audio.play3d('plasma_fire', this.position)
    }
  }

  // === PICKUPS ===
  object HealthPack @pointable @networked {
    geometry: 'model/health_pack.glb'
    @networked active: true
    respawnTime: 15000

    animation float { property: 'position.y', from: 0.5, to: 0.8, duration: 1500, loop: infinite }

    onPoint(player): {
      if (!this.active) return
      player.health = Math.min(player.health + 50, 100)
      this.active = false
      this.visible = false
      setTimeout(() => { this.active = true; this.visible = true }, this.respawnTime)
    }
  }

  // === GAME MANAGER ===
  controller GameManager @networked {
    @networked state: 'warmup'
    @networked scores: { alpha: 0, beta: 0 }
    @networked timeRemaining: 0

    config: { roundTime: 300000, scoreToWin: 50 }

    stateMachine GameState {
      initial: 'warmup'
      states: {
        warmup: { after: 30000 -> 'playing' }
        playing: {
          enter: { this.timeRemaining = this.config.roundTime }
          tick: { this.timeRemaining -= deltaTime }
          transitions: { timeUp: { when: () => this.timeRemaining <= 0, to: 'gameOver' } }
        }
        gameOver: { enter: { ui.showAll('gameOverOverlay') } }
      }
    }

    onPlayerKill(killer, victim): {
      this.scores[killer.team]++
      ui.killfeed.add({ killer: killer.name, victim: victim.name })
    }
  }

  // === UI ===
  ui GameHUD {
    anchor: 'screen'

    children: {
      text Timer {
        position: [0.5, 0.95, 0]
        content: () => formatTime(game.timeRemaining)
        fontSize: 32
      }

      text Scores {
        position: [0.5, 0.9, 0]
        content: () => `ALPHA: ${game.scores.alpha} | BETA: ${game.scores.beta}`
      }

      bar Health {
        position: [0.5, 0.08, 0]
        current: () => player.health
        max: 100
        color: '#22c55e'
      }

      list Killfeed {
        position: [0.95, 0.8, 0]
        maxItems: 5
      }
    }
  }
}

function formatTime(ms) {
  let s = Math.floor(ms / 1000)
  return `${Math.floor(s / 60)}:${(s % 60).toString().padStart(2, '0')}`
}
